-- ============================================================================
-- V62 - Catalog sync (generated from Unity skins.json + cases.json)
-- ============================================================================
-- Cases-only sync: upserts cases and rebuilds their drop pools and rarity
-- weights. Skins (and their vp_value) are left untouched. Touches catalog
-- tables only; never deletes players, inventory, wallets, or history.
-- Generated by tools/catalog/generate_catalog_migration.py --cases-only.
-- ============================================================================

-- Cases (20). Upsert by primary key id.
ON CONFLICT (id) DO UPDATE SET
    display_name = EXCLUDED.display_name,
    price_vp     = EXCLUDED.price_vp,
    image_ref    = EXCLUDED.image_ref,
    active       = EXCLUDED.active;

-- Rebuild the drop pools of the cases in this sync only. Nothing references
-- case_entries, so deleting and reinserting them is safe.
DELETE FROM case_entries WHERE case_id IN ('vandal_basic', 'vandal_protocol', 'vandal_radiant', 'vandal_arcane', 'melee_arcane', 'melee_basic', 'melee_protocol', 'melee_radiant', 'ghost_basic', 'ghost_radiant', 'ghost_protocol', 'ghost_arcane', 'classic_basic', 'classic_protocol', 'classic_arcane', 'classic_radiant', 'bulldog_basic', 'bulldog_protocol', 'bulldog_radiant', 'bulldog_arcane');

-- Drop-pool entries (3153).

-- Rebuild authored rarity weights (rarity-first roll odds) for these cases.
DELETE FROM case_rarity_weights WHERE case_id IN ('vandal_basic', 'vandal_protocol', 'vandal_radiant', 'vandal_arcane', 'melee_arcane', 'melee_basic', 'melee_protocol', 'melee_radiant', 'ghost_basic', 'ghost_radiant', 'ghost_protocol', 'ghost_arcane', 'classic_basic', 'classic_protocol', 'classic_arcane', 'classic_radiant', 'bulldog_basic', 'bulldog_protocol', 'bulldog_radiant', 'bulldog_arcane');
-- Rarity weights (111).
